import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.eQLvDOR_.js";const f=JSON.parse('{"title":"workflows-vs-agents","description":"","frontmatter":{"title":"workflows-vs-agents","connection":"Workflows vs Agents 分析","connection_id":"workflows-vs-agents-analysis","related_concepts":["[[workflows-vs-agents]]","[[agentic-patterns]]","[[agent-harness-pattern]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/connections/workflows-vs-agents.md","filePath":"wiki/connections/workflows-vs-agents.md","lastUpdated":null}'),l={name:"wiki/connections/workflows-vs-agents.md"};function r(o,t,i,d,g,c){return a(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="架构对比-workflows-对比-agents" tabindex="-1">架构对比：Workflows 对比 Agents <a class="header-anchor" href="#架构对比-workflows-对比-agents" aria-label="Permalink to &quot;架构对比：Workflows 对比 Agents&quot;">​</a></h1><h2 id="深度分析" tabindex="-1">深度分析 <a class="header-anchor" href="#深度分析" aria-label="Permalink to &quot;深度分析&quot;">​</a></h2><p>在构建 AI 智能体系统时，最常见的错误是过早地引入“完全自主的 Agent”。根据 Anthropic 的经验，<strong>Workflows (工作流)</strong> 往往是 80% 场景下的最优解。</p><h3 id="决策矩阵" tabindex="-1">决策矩阵 <a class="header-anchor" href="#决策矩阵" aria-label="Permalink to &quot;决策矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;"><strong>Workflows</strong></th><th style="text-align:left;"><strong>Autonomous Agents</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>可预测性</strong></td><td style="text-align:left;">极高 (由于由于代码控制)</td><td style="text-align:left;">较低 (由于由于 LLM 动态决策)</td></tr><tr><td style="text-align:left;"><strong>纠错机制</strong></td><td style="text-align:left;">预定义的 Gate 检查</td><td style="text-align:left;">运行时的 Ground Truth 校验与重试</td></tr><tr><td style="text-align:left;"><strong>调试难度</strong></td><td style="text-align:left;">容易 (有明确的任务边界)</td><td style="text-align:left;">困难 (存在复合幻觉)</td></tr><tr><td style="text-align:left;"><strong>Token 消耗</strong></td><td style="text-align:left;">相对较低且可控</td><td style="text-align:left;">可能因死循环而失控</td></tr></tbody></table><h3 id="混合架构建议" tabindex="-1">混合架构建议 <a class="header-anchor" href="#混合架构建议" aria-label="Permalink to &quot;混合架构建议&quot;">​</a></h3><p>在生产环境中，最有效的做法是<strong>以 Workflow 为骨架，在原子节点上嵌入特定模式的 Agent</strong>：</p><ul><li>使用 <strong>Routing</strong> 确定意图。</li><li>使用 <strong>Prompt Chaining</strong> 处理结构化转换。</li><li>仅在需要高度灵活性（如文件系统大规模修改）时，才切换到 <strong>Orchestrator-Workers</strong> 模式。</li></ul><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>不要追求“最聪明”的模型做最复杂的事，而要追求“最稳定”的架构。</p><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Building Effective AI Agents.html">[Agent_Architecture] Building Effective AI Agents</a></li></ul>',13)])])}const u=e(l,[["render",r]]);export{f as __pageData,u as default};
